import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
// 引入我们的领域对象工厂
import { createSudoku, createGame } from '../../../domain/index.js';

// ==========================================
// 适配层：将 Game 领域对象包装进 Svelte Writable
// ==========================================
const domainGameStore = writable(null);
const baseGridStore = writable(Array(9).fill().map(() => Array(9).fill(0)));

export const domainGame = {
    subscribe: domainGameStore.subscribe,

    init(sudokuArray) {
        baseGridStore.set(JSON.parse(JSON.stringify(sudokuArray)));
        const sudoku = createSudoku(sudokuArray);
        domainGameStore.set(createGame({ sudoku }));
    },

    guess(row, col, value) {
        // 使用 update 创建新的引用，触发 Svelte 的响应式更新
        domainGameStore.update(g => {
            if (g) g.guess({ row, col, value });
            return g;
        });
    },

    undo() {
        domainGameStore.update(g => {
            if (g && g.canUndo()) g.undo();
            return g;
        });
    },

    redo() {
        domainGameStore.update(g => {
            if (g && g.canRedo()) g.redo();
            return g;
        });
    }
};

// ==========================================
// 对外暴露出和旧版完全一致的接口供 Svelte 消费
// ==========================================

// grid 作为初始底盘暴漏给外层渲染
export const grid = {
    subscribe: baseGridStore.subscribe,
    generate(difficulty) {
        domainGame.init(generateSudoku(difficulty));
    },
    decodeSencode(sencode) {
        domainGame.init(decodeSencode(sencode));
    },
    get(gridStore, x, y) {
        return gridStore[y][x];
    },
    getSencode(gridStore) {
        return encodeSudoku(gridStore);
    }
};

// userGrid 不再自己管理二维数组，而是作为 domainGame 的 derived store
export const userGrid = {
    subscribe: derived(
        [baseGridStore, domainGameStore],
        ([$baseGrid, $domainGame]) => {
            return $domainGame ? $domainGame.getSudoku().getGrid() : $baseGrid;
        }
    ).subscribe,

    set: (pos, value) => {
        // 关键：原本直接改数组的代码，现在路由到领域对象
        domainGame.guess(pos.y, pos.x, value);
    },

    applyHint: (pos) => {
        hints.useHint();
        let currentGrid;
        domainGameStore.subscribe(g => currentGrid = g ? g.getSudoku().getGrid() : [])();

        if (currentGrid.length > 0) {
            const solvedSudoku = solveSudoku(currentGrid);
            domainGame.guess(pos.y, pos.x, solvedSudoku[pos.y][pos.x]);
        }
    }
};

// invalidCells 的校验能力已转移至领域模型，这里仅做派生
export const invalidCells = derived(domainGameStore, $g => {
    return $g ? $g.getSudoku().getInvalidCells() : [];
});

// 新增暴露 Undo / Redo 状态供 UI 判断
export const canUndo = derived(domainGameStore, $g => $g ? $g.canUndo() : false);
export const canRedo = derived(domainGameStore, $g => $g ? $g.canRedo() : false);